  const isHidden = wrap.classList.contains('ddc-hidden') || wrap.style.display === 'none' || wrap.inert === true;
  return {
    changed: wasHidden !== isHidden,
    becameVisible: wasHidden && !isHidden,
    becameHidden: !wasHidden && isHidden,
    visible: !isHidden,
  };
